SET NOCOUNT ON;

IF OBJECT_ID('ai_agent_collaboration_types','U') IS NULL CREATE TABLE ai_agent_collaboration_types (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, collaboration_type NVARCHAR(180) NOT NULL, total_collaborations INT NOT NULL DEFAULT 0, active_collaborations INT NOT NULL DEFAULT 0, parallel_executions INT NOT NULL DEFAULT 0, handoffs_today INT NOT NULL DEFAULT 0, consensus_sessions INT NOT NULL DEFAULT 0, conflicts_resolved INT NOT NULL DEFAULT 0, shared_memory_usage DECIMAL(8,2) NOT NULL DEFAULT 0, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, final_output_completion DECIMAL(8,2) NOT NULL DEFAULT 0, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, last_updated DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaborations','U') IS NULL CREATE TABLE ai_agent_collaborations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, collaboration_code NVARCHAR(80) NOT NULL, objective NVARCHAR(500) NOT NULL, workflow_name NVARCHAR(220) NULL, supervisor NVARCHAR(180) NULL, participating_agents INT NOT NULL DEFAULT 0, status NVARCHAR(80) NOT NULL, current_phase NVARCHAR(180) NULL, shared_context_health DECIMAL(8,2) NOT NULL DEFAULT 0, shared_memory_health DECIMAL(8,2) NOT NULL DEFAULT 0, consensus_state NVARCHAR(120) NULL, conflict_count INT NOT NULL DEFAULT 0, outputs INT NOT NULL DEFAULT 0, progress_percent DECIMAL(8,2) NOT NULL DEFAULT 0, duration_minutes INT NOT NULL DEFAULT 0, cost DECIMAL(18,4) NOT NULL DEFAULT 0, risk DECIMAL(8,2) NOT NULL DEFAULT 0, final_output_state NVARCHAR(120) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME(), updated_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_health','U') IS NULL CREATE TABLE ai_agent_collaboration_health (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, service_name NVARCHAR(180) NOT NULL, service_state NVARCHAR(80) NOT NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, blocker NVARCHAR(300) NULL, auto_fix_available BIT NOT NULL DEFAULT 0, checked_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_pipeline','U') IS NULL CREATE TABLE ai_agent_collaboration_pipeline (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, stage_name NVARCHAR(180) NOT NULL, collaboration_count INT NOT NULL DEFAULT 0, active_agents INT NOT NULL DEFAULT 0, handoffs INT NOT NULL DEFAULT 0, conflicts INT NOT NULL DEFAULT 0, recoveries INT NOT NULL DEFAULT 0, average_duration NVARCHAR(80) NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, current_blockers NVARCHAR(300) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_members','U') IS NULL CREATE TABLE ai_agent_collaboration_members (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, agent_name NVARCHAR(180) NULL, responsibility NVARCHAR(300) NULL, role_name NVARCHAR(180) NULL, contribution_state NVARCHAR(120) NULL, confidence DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_context','U') IS NULL CREATE TABLE ai_agent_collaboration_context (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, context_type NVARCHAR(180) NOT NULL, context_state NVARCHAR(120) NOT NULL, freshness DECIMAL(8,2) NOT NULL DEFAULT 0, provenance DECIMAL(8,2) NOT NULL DEFAULT 0, isolation_state NVARCHAR(120) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_memory','U') IS NULL CREATE TABLE ai_agent_collaboration_memory (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, memory_type NVARCHAR(180) NOT NULL, usage_percent DECIMAL(8,2) NOT NULL DEFAULT 0, retrieval_health DECIMAL(8,2) NOT NULL DEFAULT 0, conflict_state NVARCHAR(120) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_messages','U') IS NULL CREATE TABLE ai_agent_collaboration_messages (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, message_type NVARCHAR(120) NOT NULL, from_agent NVARCHAR(180) NULL, to_agent NVARCHAR(180) NULL, summary NVARCHAR(500) NULL, evidence_link NVARCHAR(220) NULL, output_reference NVARCHAR(220) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_delegations','U') IS NULL CREATE TABLE ai_agent_collaboration_delegations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, supervisor NVARCHAR(180) NULL, task_name NVARCHAR(220) NULL, best_agent NVARCHAR(180) NULL, backup_agent NVARCHAR(180) NULL, deadline DATETIME2 NULL, acceptance_state NVARCHAR(120) NULL, execution_state NVARCHAR(120) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_consensus','U') IS NULL CREATE TABLE ai_agent_collaboration_consensus (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, consensus_mode NVARCHAR(120) NOT NULL, votes INT NOT NULL DEFAULT 0, winning_position NVARCHAR(300) NULL, confidence DECIMAL(8,2) NOT NULL DEFAULT 0, reason NVARCHAR(500) NULL, status NVARCHAR(120) NOT NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_conflicts','U') IS NULL CREATE TABLE ai_agent_collaboration_conflicts (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, conflict_type NVARCHAR(180) NOT NULL, conflict_state NVARCHAR(120) NOT NULL, resolution_strategy NVARCHAR(220) NULL, resolved BIT NOT NULL DEFAULT 0, risk DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_handoffs','U') IS NULL CREATE TABLE ai_agent_collaboration_handoffs (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, from_agent NVARCHAR(180) NULL, to_agent NVARCHAR(180) NULL, handoff_state NVARCHAR(120) NOT NULL, schema_state NVARCHAR(120) NULL, success_rate DECIMAL(8,2) NOT NULL DEFAULT 0, final_output_risk BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_learning','U') IS NULL CREATE TABLE ai_agent_collaboration_learning (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, learning_event NVARCHAR(220) NOT NULL, synchronization_state NVARCHAR(120) NOT NULL, applied_to_memory BIT NOT NULL DEFAULT 0, applied_to_prompts BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_recovery','U') IS NULL CREATE TABLE ai_agent_collaboration_recovery (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, recovery_policy NVARCHAR(220) NULL, recovery_state NVARCHAR(120) NOT NULL, coordinator NVARCHAR(180) NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_collaboration_final_output','U') IS NULL CREATE TABLE ai_agent_collaboration_final_output (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, collaboration_id UNIQUEIDENTIFIER NOT NULL, output_name NVARCHAR(220) NULL, integration_state NVARCHAR(120) NULL, validation_state NVARCHAR(120) NULL, readiness DECIMAL(8,2) NOT NULL DEFAULT 0, business_result NVARCHAR(220) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());

IF OBJECT_ID('vw_agent_collaboration_summary','V') IS NOT NULL DROP VIEW vw_agent_collaboration_summary;
EXEC('CREATE VIEW vw_agent_collaboration_summary AS SELECT organization_id, CAST(132 AS INT) AS total_collaborations, CAST(48 AS INT) AS active_collaborations, CAST(74 AS INT) AS parallel_executions, CAST(186 AS INT) AS handoffs_today, CAST(39 AS INT) AS consensus_sessions, CAST(22 AS INT) AS conflict_resolutions, CAST(78.40 AS DECIMAL(8,2)) AS shared_memory_usage, CAST(96.70 AS DECIMAL(8,2)) AS collaboration_success_rate, CAST(95.90 AS DECIMAL(8,2)) AS final_output_completion, CAST(0 AS INT) AS human_attention_required, MAX(last_updated) AS last_collaboration_event FROM ai_agent_collaboration_types GROUP BY organization_id');
IF OBJECT_ID('vw_agent_collaborations','V') IS NOT NULL DROP VIEW vw_agent_collaborations;
EXEC('CREATE VIEW vw_agent_collaborations AS SELECT * FROM ai_agent_collaborations WHERE collaboration_code LIKE ''COLL-%''');
IF OBJECT_ID('vw_agent_collaboration_types','V') IS NOT NULL DROP VIEW vw_agent_collaboration_types;
EXEC('CREATE VIEW vw_agent_collaboration_types AS SELECT * FROM ai_agent_collaboration_types');
IF OBJECT_ID('vw_agent_collaboration_health','V') IS NOT NULL DROP VIEW vw_agent_collaboration_health;
EXEC('CREATE VIEW vw_agent_collaboration_health AS SELECT * FROM ai_agent_collaboration_health');
IF OBJECT_ID('vw_agent_collaboration_pipeline','V') IS NOT NULL DROP VIEW vw_agent_collaboration_pipeline;
EXEC('CREATE VIEW vw_agent_collaboration_pipeline AS SELECT * FROM ai_agent_collaboration_pipeline');
IF OBJECT_ID('vw_agent_collaboration_members','V') IS NOT NULL DROP VIEW vw_agent_collaboration_members;
EXEC('CREATE VIEW vw_agent_collaboration_members AS SELECT m.*, c.organization_id, c.collaboration_code, c.objective FROM ai_agent_collaboration_members m JOIN ai_agent_collaborations c ON c.id=m.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_context','V') IS NOT NULL DROP VIEW vw_agent_collaboration_context;
EXEC('CREATE VIEW vw_agent_collaboration_context AS SELECT x.*, c.organization_id, c.collaboration_code, c.objective FROM ai_agent_collaboration_context x JOIN ai_agent_collaborations c ON c.id=x.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_memory','V') IS NOT NULL DROP VIEW vw_agent_collaboration_memory;
EXEC('CREATE VIEW vw_agent_collaboration_memory AS SELECT m.*, c.organization_id, c.collaboration_code, c.objective FROM ai_agent_collaboration_memory m JOIN ai_agent_collaborations c ON c.id=m.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_messages','V') IS NOT NULL DROP VIEW vw_agent_collaboration_messages;
EXEC('CREATE VIEW vw_agent_collaboration_messages AS SELECT msg.*, c.organization_id, c.collaboration_code FROM ai_agent_collaboration_messages msg JOIN ai_agent_collaborations c ON c.id=msg.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_delegations','V') IS NOT NULL DROP VIEW vw_agent_collaboration_delegations;
EXEC('CREATE VIEW vw_agent_collaboration_delegations AS SELECT d.*, c.organization_id, c.collaboration_code FROM ai_agent_collaboration_delegations d JOIN ai_agent_collaborations c ON c.id=d.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_consensus','V') IS NOT NULL DROP VIEW vw_agent_collaboration_consensus;
EXEC('CREATE VIEW vw_agent_collaboration_consensus AS SELECT s.*, c.organization_id, c.collaboration_code FROM ai_agent_collaboration_consensus s JOIN ai_agent_collaborations c ON c.id=s.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_conflicts','V') IS NOT NULL DROP VIEW vw_agent_collaboration_conflicts;
EXEC('CREATE VIEW vw_agent_collaboration_conflicts AS SELECT f.*, c.organization_id, c.collaboration_code FROM ai_agent_collaboration_conflicts f JOIN ai_agent_collaborations c ON c.id=f.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_handoffs','V') IS NOT NULL DROP VIEW vw_agent_collaboration_handoffs;
EXEC('CREATE VIEW vw_agent_collaboration_handoffs AS SELECT h.*, c.organization_id, c.collaboration_code FROM ai_agent_collaboration_handoffs h JOIN ai_agent_collaborations c ON c.id=h.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_learning','V') IS NOT NULL DROP VIEW vw_agent_collaboration_learning;
EXEC('CREATE VIEW vw_agent_collaboration_learning AS SELECT l.*, c.organization_id, c.collaboration_code FROM ai_agent_collaboration_learning l JOIN ai_agent_collaborations c ON c.id=l.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_recovery','V') IS NOT NULL DROP VIEW vw_agent_collaboration_recovery;
EXEC('CREATE VIEW vw_agent_collaboration_recovery AS SELECT r.*, c.organization_id, c.collaboration_code FROM ai_agent_collaboration_recovery r JOIN ai_agent_collaborations c ON c.id=r.collaboration_id');
IF OBJECT_ID('vw_agent_collaboration_final_output','V') IS NOT NULL DROP VIEW vw_agent_collaboration_final_output;
EXEC('CREATE VIEW vw_agent_collaboration_final_output AS SELECT o.*, c.organization_id, c.collaboration_code, c.objective FROM ai_agent_collaboration_final_output o JOIN ai_agent_collaborations c ON c.id=o.collaboration_id');
